@import url('https://fonts.googleapis.com/css2?family=Poppins:wght@300;400;500;600;700&display=swap');

.landing-page {
  font-family: 'Poppins', sans-serif;
  color: #f5f5f5;
  background: #0a1628;
}

/* Header */
.header {
  background: linear-gradient(180deg, #0a1628 0%, #0d1d35 100%);
  padding: 1.5rem 0;
  border-bottom: 1px solid rgba(212, 175, 55, 0.3);
  position: sticky;
  top: 0;
  z-index: 100;
  backdrop-filter: blur(10px);
}

.header-content {
  display: flex;
  justify-content: space-between;
  align-items: center;
  flex-wrap: wrap;
  gap: 1.5rem;
}

.logo-section {
  display: flex;
  align-items: center;
}

.brand-text {
  display: flex;
  flex-direction: column;
  gap: 0.25rem;
}

.brand-name {
  font-size: 1.8rem;
  font-weight: 700;
  letter-spacing: 6px;
  color: #d4af37;
  margin: 0;
  text-shadow: 0 2px 8px rgba(212, 175, 55, 0.3);
  transition: text-shadow 0.3s ease;
}

.brand-name:hover {
  text-shadow: 0 4px 12px rgba(212, 175, 55, 0.5);
}

.brand-tagline {
  font-size: 0.85rem;
  color: #b8a16f;
  letter-spacing: 1.5px;
  margin: 0;
  font-weight: 400;
}

.nav {
  display: flex;
  gap: 2rem;
  flex-wrap: wrap;
}

.nav-link {
  color: #d4af37;
  text-decoration: none;
  font-weight: 500;
  letter-spacing: 1px;
  font-size: 0.9rem;
  transition: color 0.3s ease, transform 0.3s ease;
  position: relative;
}

.nav-link::after {
  content: '';
  position: absolute;
  bottom: -4px;
  left: 0;
  width: 0;
  height: 2px;
  background: #d4af37;
  transition: width 0.3s ease;
}

.nav-link:hover {
  color: #f5e6b3;
  transform: translateY(-2px);
}

.nav-link:hover::after {
  width: 100%;
}

/* Hero Section */
.hero {
  padding: 6rem 0;
  background: linear-gradient(135deg, #0a1628 0%, #0d1d35 50%, #0a1628 100%);
  position: relative;
  overflow: hidden;
}

.hero::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: radial-gradient(circle at 30% 50%, rgba(212, 175, 55, 0.05) 0%, transparent 50%);
