.hero-content {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 4rem;
  align-items: center;
  position: relative;
  z-index: 1;
}

.hero-text {
  animation: fadeInLeft 1s ease;
}

.hero-title {
  font-size: 3.5rem;
  font-weight: 700;
  color: #d4af37;
  margin-bottom: 1.5rem;
  letter-spacing: 2px;
  line-height: 1.2;
}

.hero-description {
  font-size: 1.2rem;
  color: #b8a16f;
  line-height: 1.8;
  margin-bottom: 2.5rem;
