  justify-content: center;
  align-items: center;
  animation: fadeInRight 1s ease;
}

.image-frame {
  position: relative;
  border-radius: 20px;
  overflow: hidden;
  box-shadow: 0 10px 40px rgba(0, 0, 0, 0.5);
  border: 3px solid #d4af37;
  transition: transform 0.3s ease, box-shadow 0.3s ease;
}

.image-frame:hover {
