  border: 1px solid rgba(212, 175, 55, 0.2);
  display: flex;
  align-items: flex-start;
  gap: 1.5rem;
  transition: border-color 0.3s ease, box-shadow 0.3s ease, transform 0.3s ease;
}

.benefit-item:hover {
  border-color: #d4af37;
  box-shadow: 0 5px 20px rgba(212, 175, 55, 0.2);
  transform: translateX(5px);
}

.benefit-icon {
  width: 28px;
  height: 28px;
  color: #d4af37;
  flex-shrink: 0;
  margin-top: 0.25rem;
}

.benefit-text {
  color: #b8a16f;
  line-height: 1.7;
  font-size: 0.95rem;
  margin: 0;
}

/* Contact Section */
.contact {
  padding: 6rem 0;
  background: linear-gradient(135deg, #0d1d35 0%, #0a1628 100%);
}

.contact-subtitle {
  text-align: center;
  font-size: 1.2rem;
  color: #b8a16f;
  margin-bottom: 4rem;
  max-width: 700px;
  margin-left: auto;
  margin-right: auto;
}

.contact-content {
  display: flex;
  justify-content: center;
  align-items: center;
}

.contact-form-card {
  background: linear-gradient(145deg, #0a1628 0%, #0d1d35 100%);
  border: 1px solid rgba(212, 175, 55, 0.3);
  max-width: 700px;
  width: 100%;
}

.form-card-title {
  color: #ffffff !important;
  font-size: 1.5rem !important;
  font-weight: 600 !important;
}

.contact-form {
  display: flex;
  flex-direction: column;
  gap: 1.5rem;
}

.form-group {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}

.form-group label {
  color: #d4af37;
  font-weight: 500;
  letter-spacing: 0.5px;
}

.form-group input,
.form-group textarea {
  background: rgba(13, 29, 53, 0.5);
  border: 1px solid rgba(212, 175, 55, 0.3);
  color: #f5f5f5;
  transition: border-color 0.3s ease, box-shadow 0.3s ease;
}

.form-group input:focus,
.form-group textarea:focus {
  border-color: #d4af37;
  box-shadow: 0 0 0 3px rgba(212, 175, 55, 0.1);
}

.submit-button {
  background: linear-gradient(135deg, #d4af37 0%, #f5e6b3 100%);
  color: #0a1628;
  font-weight: 600;
  letter-spacing: 1.5px;
  transition: transform 0.3s ease, box-shadow 0.3s ease;
  border: none;
}

.submit-button:hover:not(:disabled) {
  transform: translateY(-2px);
  box-shadow: 0 5px 20px rgba(212, 175, 55, 0.5);
  background: linear-gradient(135deg, #f5e6b3 0%, #d4af37 100%);
}

.submit-button:disabled {
  opacity: 0.6;
  cursor: not-allowed;
}

.contact-info {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
}

.whatsapp-qr-section {
  background: linear-gradient(145deg, #0a1628 0%, #0d1d35 100%);
  border: 2px solid rgba(212, 175, 55, 0.3);
  border-radius: 20px;
  padding: 2.5rem;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 1.5rem;
  transition: border-color 0.3s ease, box-shadow 0.3s ease, transform 0.3s ease;
  text-align: center;
}

.whatsapp-qr-section:hover {
  border-color: #d4af37;
  box-shadow: 0 8px 30px rgba(212, 175, 55, 0.3);
  transform: translateY(-5px);
}

.whatsapp-title {
  color: #d4af37;
  font-size: 1.5rem;
  font-weight: 600;
  margin: 0;
  letter-spacing: 1px;
}

.qr-code-link {
  display: block;
  transition: transform 0.3s ease, filter 0.3s ease;
  cursor: default;
}

.whatsapp-qr-code {
  width: 250px;
  height: 250px;
  border-radius: 15px;
  border: 3px solid #d4af37;
  background: white;
  padding: 10px;
  transition: transform 0.3s ease, box-shadow 0.3s ease;
}

.whatsapp-qr-code:hover {
  transform: scale(1.03);
  box-shadow: 0 8px 20px rgba(212, 175, 55, 0.3);
}

.whatsapp-instruction {
  color: #b8a16f;
  font-size: 1rem;
  margin: 0;
  letter-spacing: 0.5px;
  font-weight: 500;
}

.whatsapp-contact-info {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
  text-align: center;
  padding-top: 1rem;
  border-top: 1px solid rgba(212, 175, 55, 0.2);
  width: 100%;
}

.phone-number {
  color: #d4af37;
  font-size: 1.3rem;
  font-weight: 600;
  margin: 0;
  letter-spacing: 1px;
}

.whatsapp-note {
  color: #b8a16f;
  font-size: 0.9rem;
  margin: 0;
  letter-spacing: 0.5px;
}

/* Footer */
.footer {
  background: #050d1a;
  padding: 2.5rem 0;
  border-top: 2px solid #d4af37;
}

.footer-content {
  text-align: center;
}

.footer-content p {
  color: #b8a16f;
  letter-spacing: 0.5px;
  margin: 0.5rem 0;
  font-size: 0.9rem;
}

.footer-rights {
  font-size: 0.85rem;
  opacity: 0.8;
}

/* Container */
.container {
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 2rem;
}

/* Animations */
@keyframes fadeInLeft {
  from {
    opacity: 0;
    transform: translateX(-30px);
  }
  to {
    opacity: 1;
    transform: translateX(0);
  }
}

@keyframes fadeInRight {
  from {
    opacity: 0;
    transform: translateX(30px);
  }
  to {
    opacity: 1;
    transform: translateX(0);
  }
}

/* Responsive Design */
@media (max-width: 1024px) {
  .hero-content,
  .contact-content {
    grid-template-columns: 1fr;
    gap: 3rem;
  }

  .hero-title {
    font-size: 2.5rem;
  }

  .section-title {
    font-size: 2.5rem;
  }
}

@media (max-width: 768px) {
  .header-content {
    flex-direction: column;
    text-align: center;
  }

  .logo-section {
    flex-direction: column;
  }

  .nav {
    flex-direction: column;
    align-items: center;
    gap: 1rem;
  }

  .hero {
    padding: 4rem 0;
  }

  .hero-title {
    font-size: 2rem;
  }

  .hero-description {
    font-size: 1rem;
  }

  .section-title {
    font-size: 2rem;
  }

  .services,
  .benefits,
  .contact {
    padding: 4rem 0;
  }

  .services-grid,
  .benefits-grid {
    grid-template-columns: 1fr;
  }
}

@media (max-width: 480px) {
  .brand-name {
    font-size: 1.2rem;
    letter-spacing: 2px;
  }

  .hero-title {
    font-size: 1.75rem;
  }

  .cta-button {
    padding: 1.2rem 2rem;
    font-size: 0.9rem;
  }
}

